import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Trash2, Edit, ArrowLeft, X, Save, 
  Loader2, Search, CheckCircle2, Box, Send, Clock, Weight, Upload, ImageIcon, Table as TableIcon, Sparkles, Image as ImageIcon2
} from 'lucide-react';

import GestionInventario from './GestionInventario'; 

// --- COMPONENTE: CARGADOR EXCEL CON BUSQUEDA DE COINCIDENCIAS ---
const CargadorMasivoPro = ({ onClose, cloudName, folder, preset, localId, onComplete, API_URL, biblioteca }) => {
  const [items, setItems] = useState([]); 
  const [subiendo, setSubiendo] = useState(false);

  // Función para buscar si una foto YA EXISTE en la base de datos por nombre
  const buscarFotoExistente = (tipo, marca, contenido) => {
    const nombreCompleto = `${tipo} ${marca} ${contenido}`.toLowerCase().trim();
    // Buscamos en la biblioteca de productos ya cargados
    const coincidencia = biblioteca.find(prod => 
      prod.producto.toLowerCase().includes(nombreCompleto) || 
      nombreCompleto.includes(prod.producto.toLowerCase())
    );
    return coincidencia ? coincidencia.publicId : null;
  };

  const handleFileChange = (e) => {
    const nuevosArchivos = Array.from(e.target.files).map(file => {
      const nombreLimpio = file.name.split('.')[0].replace(/[-_.]/g, ' ');
      const partes = nombreLimpio.split(' ');
      return {
        file,
        preview: URL.createObjectURL(file),
        tipo: partes[0] || '',
        marca: partes[1] || '',
        contenido: partes.slice(2).join(' ') || '',
        precio: '',
        stock: '',
        publicIdExistente: null, // Si ya existe en la nube, no la resubimos
        subido: false,
        error: false
      };
    });
    setItems([...items, ...nuevosArchivos]);
  };

  const updateItem = (index, field, value) => {
    const newItems = [...items];
    newItems[index][field] = value;
    
    // Si cambia el nombre, intentamos buscar si ya tenemos esa foto en la biblioteca
    if (field === 'tipo' || field === 'marca') {
      const idEncontrado = buscarFotoExistente(newItems[index].tipo, newItems[index].marca, newItems[index].contenido);
      newItems[index].publicIdExistente = idEncontrado;
    }
    
    setItems(newItems);
  };

  const procesarCarga = async () => {
    setSubiendo(true);
    for (let i = 0; i < items.length; i++) {
      if (items[i].subido) continue;

      try {
        let publicIdFinal = items[i].publicIdExistente;

        // SOLO SUBIMOS A CLOUDINARY SI NO ENCONTRAMOS UNA FOTO PREVIA
        if (!publicIdFinal) {
          const formData = new FormData();
          formData.append('file', items[i].file);
          formData.append('upload_preset', preset);
          formData.append('folder', folder);
          const resCloud = await axios.post(
            `https://api.cloudinary.com/v1_1/${cloudName}/image/upload`,
            formData
          );
          publicIdFinal = resCloud.data.public_id;
        }

        const nuevoProducto = {
          producto: `${items[i].tipo} ${items[i].marca} ${items[i].contenido}`.trim(),
          publicId: publicIdFinal,
          local: localId,
          precioNuevo: Number(items[i].precio),
          stock: Number(items[i].stock) || 0,
          publicado: false,
          categoria: 'Almacén'
        };

        await axios.post(`${API_URL}/api/ofertas`, nuevoProducto);
        
        const newItems = [...items];
        newItems[i].subido = true;
        setItems([...newItems]);
      } catch (err) {
        const newItems = [...items];
        newItems[i].error = true;
        setItems([...newItems]);
      }
    }
    setSubiendo(false);
    onComplete();
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '95%', maxWidth: '1100px', maxHeight: '90vh', display: 'flex', flexDirection: 'column'}}>
        <div style={modalHeader}>
          <div style={{display:'flex', alignItems:'center', gap:10}}>
            <Sparkles size={24} color="#8b5cf6"/>
            <h3 style={titleStyle}>Carga Inteligente & Biblioteca de Fotos</h3>
          </div>
          <button onClick={onClose} style={closeBtn}><X /></button>
        </div>

        <div style={{padding: '0 20px 20px', flex: 1, overflowY: 'auto'}}>
          <div style={infoBox}>
            <input type="file" multiple accept="image/*" onChange={handleFileChange} id="bulk-pro" style={{display:'none'}} />
            <label htmlFor="bulk-pro" style={btnPlus}> <Plus size={18}/> Cargar Nuevas Fotos </label>
            <p style={{margin:0, fontSize:'0.85rem', color:'#1e40af'}}>
              <b>Modo Inteligente:</b> Si el nombre coincide con un producto anterior, el sistema usará la foto de la biblioteca automáticamente.
            </p>
          </div>

          <table style={excelTable}>
            <thead>
              <tr style={excelThRow}>
                <th style={excelTh}>Imagen / Origen</th>
                <th style={excelTh}>Producto</th>
                <th style={excelTh}>Marca</th>
                <th style={excelTh}>Contenido</th>
                <th style={excelTh}>Precio $</th>
                <th style={excelTh}>Estado</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item, idx) => (
                <tr key={idx} style={item.subido ? {background: '#f0fdf4'} : {}}>
                  <td style={excelTd}>
                    <div style={{position:'relative'}}>
                      <img src={item.publicIdExistente ? `https://res.cloudinary.com/${cloudName}/image/upload/w_50,h_50,c_thumb/v1/${item.publicIdExistente}` : item.preview} style={tableImg} alt="p" />
                      {item.publicIdExistente && <div title="Foto recuperada de biblioteca" style={badgeLib}><ImageIcon2 size={10}/></div>}
                    </div>
                  </td>
                  <td style={excelTd}><input style={tableInput} value={item.tipo} onChange={e => updateItem(idx, 'tipo', e.target.value)} /></td>
                  <td style={excelTd}><input style={tableInput} value={item.marca} onChange={e => updateItem(idx, 'marca', e.target.value)} /></td>
                  <td style={excelTd}><input style={tableInput} value={item.contenido} onChange={e => updateItem(idx, 'contenido', e.target.value)} /></td>
                  <td style={excelTd}><input style={{...tableInput, fontWeight:'bold', color:'#0284c7'}} type="number" value={item.precio} onChange={e => updateItem(idx, 'precio', e.target.value)} /></td>
                  <td style={{...excelTd, textAlign:'center'}}>
                    {item.subido ? <CheckCircle2 color="#10b981" size={20}/> : item.publicIdExistente ? <Sparkles color="#8b5cf6" size={20}/> : <Clock color="#94a3b8" size={20}/>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div style={footerCargador}>
          <button onClick={onClose} style={btnBack}>Cancelar</button>
          <button onClick={procesarCarga} disabled={subiendo || items.length === 0} style={{...btnSave, width: '300px'}}>
            {subiendo ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
            {subiendo ? 'Guardando...' : 'Sincronizar con Inventario'}
          </button>
        </div>
      </div>
    </div>
  );
};

// --- COMPONENTE PRINCIPAL ---
const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCargador, setShowCargador] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");

  const CLOUD_NAME = "dwpgncjgn";
  const CARPETA_NUEVA = "PRODUCTOS"; 
  const PRESET_NAME = "PRODUCTOS"; 
  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  const cargarOfertas = useCallback(async () => {
    if (!localId) return;
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setOfertas(res.data);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  }, [localId, API_URL]);

  useEffect(() => { cargarOfertas(); }, [cargarOfertas]);

  return (
    <div style={containerStyle}>
      <div style={headerStyle}>
        <div>
          <h1 style={titleStyle}>Mi Inventario Inteligente</h1>
          <p style={subtitleStyle}>Las fotos subidas se guardan como referencia para futuras cargas.</p>
        </div>
        <button onClick={() => setShowCargador(true)} style={btnCloud}>
          <Sparkles size={20}/> CARGA MASIVA / EXCEL
        </button>
      </div>

      <div style={searchBarContainer}>
        <Search size={20} color="#94a3b8" style={searchIcon} />
        <input style={searchInput} placeholder="Buscar en mi biblioteca de productos..." onChange={e => setSearchTerm(e.target.value)} />
      </div>

      <div style={gridStyle}>
        {loading ? <Loader2 className="animate-spin" /> : ofertas.filter(o => o.producto.toLowerCase().includes(searchTerm.toLowerCase())).map(o => (
          <div key={o._id} style={itemCard}>
            <div style={imageContainerStyle}>
              <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/f_auto,q_auto/v1/${o.publicId}`} style={imageStyle} alt={o.producto} />
            </div>
            <h4 style={prodName}>{o.producto}</h4>
            <div style={priceContainer}><span style={currentPrice}>${o.precioNuevo}</span></div>
          </div>
        ))}
      </div>

      {showCargador && (
        <CargadorMasivoPro 
          cloudName={CLOUD_NAME} folder={CARPETA_NUEVA} preset={PRESET_NAME} 
          localId={localId} API_URL={API_URL} onComplete={cargarOfertas}
          onClose={() => setShowCargador(false)} 
          biblioteca={ofertas} // Pasamos los productos actuales como "biblioteca"
        />
      )}
    </div>
  );
};

// --- ESTILOS ADICIONALES ---
const infoBox = { display:'flex', alignItems:'center', gap: 15, marginBottom: 20, background: '#eff6ff', padding: '15px', borderRadius: '15px', border: '1px solid #bfdbfe' };
const badgeLib = { position:'absolute', bottom:-5, right:-5, background:'#8b5cf6', color:'white', borderRadius:'50%', width:18, height:18, display:'flex', alignItems:'center', justifyContent:'center', border:'2px solid white' };
const excelTable = { width: '100%', borderCollapse: 'collapse' };
const excelThRow = { background: '#f8fafc', textAlign: 'left' };
const excelTh = { padding: '12px', color: '#64748b', fontSize: '0.7rem', textTransform: 'uppercase' };
const excelTd = { padding: '8px', borderBottom: '1px solid #f1f5f9' };
const tableInput = { width: '100%', padding: '10px', border: '1px solid #e2e8f0', borderRadius: '8px', fontSize: '0.85rem' };
const tableImg = { width: '50px', height: '50px', objectFit: 'cover', borderRadius: '10px' };
const footerCargador = { padding: '20px', borderTop: '1px solid #e2e8f0', display: 'flex', justifyContent: 'flex-end', gap: '15px' };
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const titleStyle = { fontSize: '1.8rem', fontWeight: '900', margin: 0 };
const subtitleStyle = { color: '#64748b' };
const btnCloud = { background: '#8b5cf6', color: 'white', border: 'none', padding: '12px 24px', borderRadius: '14px', fontWeight: '700', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '10px' };
const searchBarContainer = { position: 'relative', marginBottom: '30px' };
const searchIcon = { position: 'absolute', left: '15px', top: '50%', transform: 'translateY(-50%)' };
const searchInput = { width: '100%', padding: '15px 15px 15px 45px', borderRadius: '15px', border: '1px solid #e2e8f0' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', borderRadius: '24px', padding: '15px', border: '1px solid #f1f5f9' };
const imageContainerStyle = { width: '100%', height: '140px', background: '#f8fafc', borderRadius: '18px', overflow: 'hidden', marginBottom: '10px' };
const imageStyle = { width: '100%', height: '100%', objectFit: 'contain' };
const prodName = { fontSize: '0.9rem', fontWeight: '700', margin: '0 0 5px 0' };
const priceContainer = { display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const currentPrice = { fontSize: '1.2rem', fontWeight: '800' };
const modalOverlay = { position: 'fixed', inset: 0, background: 'rgba(15, 23, 42, 0.8)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000, backdropFilter: 'blur(8px)' };
const modalContent = { background: 'white', borderRadius: '28px' };
const modalHeader = { padding: '25px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const closeBtn = { background: '#f1f5f9', border: 'none', borderRadius: '50%', padding: '8px', cursor: 'pointer' };
const btnPlus = { background: '#0f172a', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', fontWeight: '600', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', fontWeight: '700', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' };
const btnSave = { background: '#0284c7', color: 'white', padding: '14px', border: 'none', borderRadius: '14px', fontWeight: '700', cursor: 'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:10 };

export default GestionOfertas;
